/*Table structure for table `gaea_report` */

DROP TABLE IF EXISTS `gaea_report`;

CREATE TABLE `gaea_report` (
  `id` bigint(11) NOT NULL AUTO_INCREMENT,
  `report_name` varchar(100) DEFAULT NULL COMMENT '名称',
  `report_code` varchar(100) DEFAULT NULL COMMENT '报表编码',
  `report_group` varchar(100) DEFAULT NULL COMMENT '分组',
  `report_type` varchar(20) DEFAULT NULL COMMENT '报表类型',
  `report_image` varchar(512) DEFAULT NULL COMMENT '报表缩略图',
  `report_desc` varchar(255) DEFAULT NULL COMMENT '报表描述',
  `report_author` varchar(512) DEFAULT NULL COMMENT '报表作者',
  `download_count` bigint(11) DEFAULT NULL COMMENT '报表下载次数',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT '0--未删除 1--已删除 DIC_NAME=DELETE_FLAG',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `version` int(8) DEFAULT NULL COMMENT '版本号',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `UNIQUE_REPORT_CODE` (`report_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=200 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

/*Data for the table `gaea_report` */

insert  into `gaea_report`(`id`,`report_name`,`report_code`,`report_group`,`report_type`,`report_image`,`report_desc`,`report_author`,`download_count`,`enable_flag`,`delete_flag`,`create_by`,`create_time`,`update_by`,`update_time`,`version`) values (194,'备份001','001','default','report_screen',NULL,'备份001','zmrid',NULL,1,0,'admin','2022-08-20 23:52:31','admin','2022-08-21 14:47:33',3),(195,'智能车间生产管控大屏','002','default','report_screen',NULL,'智能车间生产管控大屏','zmrid',0,1,0,'admin','2022-08-20 23:54:23','admin','2022-08-23 21:51:38',4),(196,'备份002','002_1661064404119','default','report_screen',NULL,NULL,'zmrid',NULL,1,0,'admin','2022-08-21 14:46:49','admin','2022-08-21 14:46:55',2),(199,'工单执行进度看板','002_1661149765819','default','report_screen',NULL,'智能车间生产管控大屏','zmrid',3,1,0,'admin','2022-08-22 14:29:39','admin','2022-08-23 22:18:49',5);

/*Table structure for table `gaea_report_dashboard` */

DROP TABLE IF EXISTS `gaea_report_dashboard`;

CREATE TABLE `gaea_report_dashboard` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '看板id',
  `report_code` varchar(50) NOT NULL COMMENT '报表编码',
  `title` varchar(254) DEFAULT NULL COMMENT '看板标题',
  `width` bigint(20) DEFAULT NULL COMMENT '宽度px',
  `height` bigint(20) DEFAULT NULL COMMENT '高度px',
  `background_color` varchar(24) DEFAULT NULL COMMENT '背景色',
  `background_image` varchar(254) DEFAULT NULL COMMENT '背景图片',
  `preset_line` varchar(4096) DEFAULT NULL COMMENT '工作台中的辅助线',
  `refresh_seconds` int(11) DEFAULT NULL COMMENT '自动刷新间隔秒',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT ' 0--未删除 1--已删除 DIC_NAME=DEL_FLAG',
  `sort` int(11) DEFAULT '0' COMMENT '排序，降序',
  `create_by` varchar(64) DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_by` varchar(64) DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `version` int(8) DEFAULT NULL COMMENT '版本号',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `UNIQUE_REPORT_CODE` (`report_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=280 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC;

