/*Table structure for table `gaea_report_dashboard_widget` */

DROP TABLE IF EXISTS `gaea_report_dashboard_widget`;

CREATE TABLE `gaea_report_dashboard_widget` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '组件id',
  `report_code` varchar(50) NOT NULL COMMENT '报表编码',
  `type` varchar(50) DEFAULT NULL COMMENT '组件类型参考字典DASHBOARD_PANEL_TYPE',
  `setup` text COMMENT '组件的渲染属性json',
  `data` text COMMENT '组件的数据属性json',
  `collapse` text COMMENT '组件的配置属性json',
  `position` text COMMENT '组件的大小位置属性json',
  `options` text COMMENT 'options配置项',
  `refresh_seconds` int(11) DEFAULT NULL COMMENT '自动刷新间隔秒',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT ' 0--未删除 1--已删除 DIC_NAME=DEL_FLAG',
  `sort` bigint(20) DEFAULT '0' COMMENT '排序，图层的概念',
  `create_by` varchar(64) DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_by` varchar(64) DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `version` int(8) DEFAULT NULL COMMENT '版本号',
  PRIMARY KEY (`id`) USING BTREE
