ectItem\r\n	    where DateDiff(dd,rwol.CreateDate,getdate())<=7\r\n		group by di.DefectItemName,CONVERT(VARCHAR(10),rwol.CreateDate,120)','[{\"name\":\"不能折叠\",\"value\":2},{\"name\":\"上色不均匀\",\"value\":1},{\"name\":\"测试\",\"value\":1}]',1,0,'admin','2022-08-21 16:56:01','admin','2022-08-21 16:56:16',2,'sql'),(74,'DefectItemAllQty','不良品总数量','','iMES','select top 1 a.DefectItemName,CAST(CAST(CAST(ISNULL(a.Qty,0) AS DECIMAL(20,2))/CAST(ISNULL(sum(rwol2.Qty),0) AS DECIMAL(20,2))*100 AS DECIMAL(20,2)) AS VARCHAR(100)) + \'%\' PassPercent,a.Qty,sum(rwol2.Qty) AllQty\r\n from (\r\n	select di.DefectItemName,sum(rwol.Qty) Qty\r\n		from Production_ReportWorkOrderList rwol\r\n		left join  Base_DefectItem di on di.DefectItem_Id = rwol.DefectItem\r\n		group by di.DefectItemCode,di.DefectItemName\r\n	) a\r\n		left join Production_ReportWorkOrderList rwol2 on 1=1\r\n		\r\n	group by a.DefectItemName,a.Qty\r\n	order by a.Qty desc','[{\"DefectItemName\":\"不能折叠\",\"PassPercent\":\"50.00%\",\"Qty\":2,\"AllQty\":4}]',1,0,'admin','2022-08-21 17:10:49','admin','2022-08-21 17:25:33',2,'sql'),(75,'Top15ReportWorkOrder','最近15条报工数据','最近15条报工数据','iMES','select top 15 CreateDate,ProductName,ReportQty,GoodQty,ISNULL(NoGoodQty,0) NoGoodQty from Production_ReportWorkOrder \r\n		order by CreateDate desc','[{\"ReportQty\":6,\"NoGoodQty\":0,\"ProductName\":\"测试产品\",\"GoodQty\":6,\"CreateDate\":\"2022-08-17 15:05:08\"},{\"ReportQty\":12,\"NoGoodQty\":0,\"ProductName\":\"HW螺丝\",\"GoodQty\":12,\"CreateDate\":\"2022-08-17 12:29:04\"},{\"ReportQty\":12,\"NoGoodQty\":0,\"ProductName\":\"HW螺丝\",\"GoodQty\":12,\"CreateDate\":\"2022-08-17 12:28:16\"},{\"ReportQty\":12,\"NoGoodQty\":0,\"ProductName\":\"测试产品\",\"GoodQty\":12,\"CreateDate\":\"2022-08-17 05:53:09\"},{\"ReportQty\":12,\"NoGoodQty\":2,\"ProductName\":\"测试产品\",\"GoodQty\":12,\"CreateDate\":\"2022-08-16 10:13:55\"}]',1,0,'admin','2022-08-21 18:31:45','admin','2022-08-21 18:31:45',1,'sql'),(76,'FromTypeWOPlanQty','不同类别工单计划数','','iMES','SELECT FromType,sum([PlanQty])PlanQty\r\n  FROM [Production_WorkOrder] wo\r\n  where FromType IS NOT NULL\r\n  AND FromType=\'${fromType}\'\r\n  GROUP BY FromType','[]',1,0,'admin','2022-08-21 18:52:42','admin','2022-08-21 19:00:40',3,'sql'),(77,'WorkOrderAllQty','工单计划数合计','','iMES','SELECT sum([PlanQty]) PlanQty\r\n  FROM [Production_WorkOrder] wo\r\n  where FromType IS NOT NULL','[{\"PlanQty\":179}]',1,0,'admin','2022-08-21 19:04:21','admin','2022-08-21 19:04:21',1,'sql'),(78,'SalaryTopList','员工绩效排行','','iMES','SELECT \r\n     top 5 UserTrueName ,SUM([Salary]) Salary\r\n  FROM  [View_SalaryReport] \r\n  GROUP BY UserTrueName','[{\"Salary\":72,\"UserTrueName\":\"测试帐号1_1\"},{\"Salary\":0,\"UserTrueName\":\"角色帐号2_1\"},{\"Salary\":576,\"UserTrueName\":\"孙可可\"}]',1,0,'admin','2022-08-21 19:23:18','admin','2022-08-21 19:23:18',1,'sql'),(79,'GoodQtyPer','良品率','','iMES','SELECT \r\nCAST(CAST(CAST(ISNULL(sum(GoodQty),0) AS DECIMAL(20,2))/CAST(ISNULL(sum(ReportQty),0) AS DECIMAL(20,2))*100 AS DECIMAL(20,0)) AS VARCHAR(100)) GoodQtyPer\r\n  FROM [Production_ReportWorkOrder]','[{\"GoodQtyPer\":\"100\"}]',1,0,'admin','2022-08-21 19:53:27','admin','2022-08-21 19:53:27',1,'sql'),(80,'SalesOrderPer','销售订单占比','','iMES','SELECT   CAST(CAST(CAST(ISNULL(COUNT(WO2.WorkOrder_Id),0) AS DECIMAL(20,2))/CAST(ISNULL(COUNT(WO.WorkOrder_Id),0) AS DECIMAL(20,2))*100 AS DECIMAL(20,0)) AS VARCHAR(100)) \r\n    SalesOrderPre\r\n  FROM [iMES].[dbo].[Production_WorkOrder] WO\r\n  LEFT JOIN Production_WorkOrder WO2 ON WO.WorkOrder_Id = WO2.WorkOrder_Id AND WO2.FromType = \'SalesOrder\'','[{\"SalesOrderPre\":\"50\"}]',1,0,'admin','2022-08-21 20:00:58','admin','2022-08-21 20:00:58',1,'sql'),(81,'ProcessPlanQty','工序计划数','','iMES','SELECT TOP 5\r\n		[ProcessName]\r\n      ,SUM([PlanQty]) [PlanQty]\r\n     \r\n  FROM [iMES].[dbo].[Production_WorkOrderList]\r\n  GROUP BY ProcessName','[{\"ProcessName\":\"焊接\",\"PlanQty\":1402},{\"ProcessName\":\"破洞\",\"PlanQty\":313}]',1,0,'admin','2022-08-21 20:07:06','admin','2022-08-21 20:07:06',1,'sql'),(82,'ProcessReportNumber','工序报工数量','','iMES','SELECT TOP 5 p.ProcessName\r\n      ,SUM([ReportQty]) ReportQty\r\n  FROM [Production_ReportWorkOrder] rwo\r\n	left join Base_Process p on rwo.Process_Id = p.Process_Id\r\n	GROUP BY P.ProcessName','[{\"ReportQty\":24,\"ProcessName\":\"焊接\"},{\"ReportQty\":30,\"ProcessName\":\"破洞\"}]',1,0,'admin','2022-08-21 20:24:23','admin','2022-08-21 20:24:23',1,'sql'),(83,'WorkOrder','工单概况','','iMES','SELECT TOP (20) [WorkOrderCode]\r\n	  ,dl.DicName Status\r\n      ,[ProductCode]\r\n      ,[ProductName]\r\n      ,[ProductStandard]\r\n      ,[PlanQty]\r\n      ,[RealQty]\r\n  FROM [iMES].[dbo].[Production_WorkOrder] wo \r\n  LEFT JOIN Sys_DictionaryList dl on wo.Status = dl.DicValue\r\n  LEFT JOIN Sys_Dictionary d on d.Dic_ID = dl.Dic_ID\r\n  WHERE d.DicNo = \'workOrderStatus\'\r\n  ORDER BY WO.CreateDate DESC','[{\"Status\":\"进行中\",\"WorkOrderCode\":\"GD202208071350530001\",\"ProductStandard\":null,\"ProductName\":\"测试产品5\",\"ProductCode\":\"CP202208012112080001\",\"PlanQty\":12,\"RealQty\":0},{\"Status\":\"已完成\",\"WorkOrderCode\":\"GD202208062336180001\",\"ProductStandard\":\"测试规格\",\"ProductName\":\"测试产品\",\"ProductCode\":\"CP202207302014290004\",\"PlanQty\":12,\"RealQty\":0},{\"Status\":\"进行中\",\"WorkOrderCode\":\"ZPGD202208142200180001-2\",\"ProductStandard\":\"测试规格\",\"ProductName\":\"测试产品\",\"ProductCode\":\"CP202207302014290004\",\"PlanQty\":12,\"RealQty\":0},{\"Status\":\"已完成\",\"WorkOrderCode\":\"ZPGD202208142200180001-1\",\"ProductStandard\":null,\"ProductName\":\"HW螺丝\",\"ProductCode\":\"CP202207301931260002\",\"PlanQty\":12,\"RealQty\":12},{\"Status\":\"未开始\",\"WorkOrderCode\":\"SCJH202208142135560001-1\",\"ProductStandard\":\"测试规格\",\"ProductName\":\"测试产品\",\"ProductCode\":\"CP202207302014290004\",\"PlanQty\":111,\"RealQty\":0},{\"Status\":\"未开始\",\"WorkOrderCode\":\"XSDD202208142044450003-2\",\"ProductStandard\":null,\"ProductName\":\"测试产品5\",\"ProductCode\":\"CP202208012112080001\",\"PlanQty\":11