/*Table structure for table `gaea_report_data_set_param` */

DROP TABLE IF EXISTS `gaea_report_data_set_param`;

CREATE TABLE `gaea_report_data_set_param` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `set_code` varchar(50) DEFAULT NULL COMMENT '数据集编码',
  `param_name` varchar(50) DEFAULT NULL COMMENT '参数名',
  `param_desc` varchar(100) DEFAULT NULL COMMENT '参数描述',
  `param_type` varchar(255) DEFAULT NULL COMMENT '参数类型，字典=',
  `sample_item` varchar(1080) DEFAULT NULL COMMENT '参数示例项',
  `required_flag` int(1) DEFAULT '1' COMMENT '0--非必填 1--必填 DIC_NAME=REQUIRED_FLAG',
  `validation_rules` varchar(2048) DEFAULT NULL COMMENT 'js校验字段值规则，满足校验返回 true',
  `order_num` int(11) DEFAULT NULL COMMENT '排序',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT '0--未删除 1--已删除 DIC_NAME=DELETE_FLAG',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `version` int(8) DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='数据集查询参数';

/*Data for the table `gaea_report_data_set_param` */

insert  into `gaea_report_data_set_param`(`id`,`set_code`,`param_name`,`param_desc`,`param_type`,`sample_item`,`required_flag`,`validation_rules`,`order_num`,`enable_flag`,`delete_flag`,`create_by`,`create_time`,`update_by`,`update_time`,`version`) values (3,'FromTypeWOPlanQty','fromType','','varchar','',1,'function verification(data){\n	//自定义脚本内容\n	//可返回true/false单纯校验键入的data正确性\n	//可返回文本，实时替换,比如当前时间等\n	//return \"2099-01-01 00:00:00\";\n	return true;\n}',NULL,1,0,'admin','2022-08-21 19:00:40','admin','2022-08-21 19:00:40',1);

/*Table structure for table `gaea_report_data_set_transform` */

DROP TABLE IF EXISTS `gaea_report_data_set_transform`;

CREATE TABLE `gaea_report_data_set_transform` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `set_code` varchar(50) DEFAULT NULL COMMENT '数据集编码',
  `transform_type` varchar(50) DEFAULT NULL COMMENT '数据转换类型，DIC_NAME=TRANSFORM_TYPE; js，javaBean，字典转换',
  `transform_script` varchar(10800) DEFAULT NULL COMMENT '数据转换script,处理逻辑',
  `order_num` int(2) DEFAULT NULL COMMENT '排序,执行数据转换顺序',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT '0--未删除 1--已删除 DIC_NAME=DELETE_FLAG',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `version` int(8) DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8 ROW_FORMAT=DYNAMIC COMMENT='数据集数据转换';

/*Data for the table `gaea_report_data_set_transform` */

/*Table structure for table `gaea_report_data_source` */

DROP TABLE IF EXISTS `gaea_report_data_source`;

CREATE TABLE `gaea_report_data_source` (
  `id` bigint(20) NOT NULL AUTO_INCREMENT,
  `source_code` varchar(100) DEFAULT NULL COMMENT '数据源编码',
  `source_name` varchar(100) DEFAULT NULL COMMENT '数据源名称',
  `source_desc` varchar(255) DEFAULT NULL COMMENT '数据源描述',
  `source_type` varchar(50) DEFAULT NULL COMMENT '数据源类型 DIC_NAME=SOURCE_TYPE; mysql，orace，sqlserver，elasticsearch，接口，javaBean，数据源类型字典中item-extend动态生成表单',
  `source_config` varchar(2048) DEFAULT NULL COMMENT '数据源连接配置json：关系库{ jdbcUrl:'''', username:'''', password:'''' } ES{ hostList:''ip1:9300,ip2:9300,ip3:9300'', clusterName:''elasticsearch_cluster'' }  接口{ apiUrl:''http://ip:port/url'', method:'''' } javaBean{ beanNamw:''xxx'' }',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT '0--未删除 1--已删除 DIC_NAME=DELETE_FLAG',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `version` int(8) DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `unique_source_code` (`source_code`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8 COMMENT='数据源管理';

/*Data for the table `gaea_report_data_source` */

insert  into `gaea_report_data_source`(`id`,`source_code`,`source_name`,`source_desc`,`source_type`,`source_config`,`enable_flag`,`delete_flag`,`create_by`,`create_time`,`update_by`,`update_time`,`version`) values (1,'mysql_ajreport','mysql数据源','','mysql','{\"driverName\":\"com.mysql.cj.jdbc.Driver\",\"jdbcUrl\":\"jdbc:mysql://127.0.0.1:3306/aj_report_init?useUnicode=true&characterEncoding=UTF-8&serverTimezone=GMT%2B8\",\"username\":\"root\",\"password\":\"514224717\"}',1,0,'admin','2021-06-30 09:48:46','admin','2022-08-19 21:06:01',2),(2,'iMES','iMES','iMES数据源','mssqlserver','{\"driverName\":\"com.microsoft.sqlserver.jdbc.SQLServerDriver\",\"jdbcUrl\":\"jdbc:sqlserver://127.0.0.1:1433;DatabaseName=iMES\",\"username\":\"sa\",\"password\":\"514224717\"}',1,0,'admin','2022-08-21 16:12:26','admin','2022-08-21 16:42:55',2);

/*Table structure for table `gaea_report_excel` */

DROP TABLE IF EXISTS `gaea_report_excel`;

CREATE TABLE `gaea_report_excel` (
  `id` bigint(11) NOT NULL AUTO_INCREMENT,
  `report_code` varchar(100) DEFAULT NULL COMMENT '报表编码',
  `set_codes` varchar(255) DEFAULT NULL COMMENT '数据集编码，以|分割',
  `set_param` varchar(1024) DEFAULT NULL COMMENT '数据集查询参数',
  `json_str` text COMMENT '报表json串',
  `enable_flag` int(1) DEFAULT '1' COMMENT '0--已禁用 1--已启用  DIC_NAME=ENABLE_FLAG',
  `delete_flag` int(1) DEFAULT '0' COMMENT '0--未删除 1--已删除 DIC_NAME=DELETE_FLAG',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `version` int(8) DEFAULT NULL COMMENT '版本号',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `UNIQUE_REPORT_CODE` (`report_code`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8;

